const amqplib = require('amqplib');

async function processPaymentEvent(channel, msg) {
  const event = JSON.parse(msg.content.toString());
  
  switch (event.type) {
    case 'PAYMENT_SUCCESS':
      console.log(`Received payment success event: ${event.id}`);
      break;
    case 'PAYMENT_FAILURE':
      console.log(`Received payment failure event: ${event.id}`);
      break;
    default:
      console.log(`Unsupported event type: ${event.type}`);
  }
}

async function main() {
  try {
    const connection = await amqplib.connect('amqp://localhost');
    const channel = await connection.createChannel();

    const exchange = 'payment_exchange';
    const queue = 'payment_queue';

    await channel.assertExchange(exchange, 'direct', { durable: true });
    await channel.assertQueue(queue, { exclusive: true });

    await channel.bindQueue(queue, exchange, '', '');

    let consumer = await channel.consume(queue, (msg) => {
      if (msg !== null) {
        processPaymentEvent(channel, msg);
        channel.ack(msg);
      }
    }, { noAck: false });

    console.log('Waiting for payment events...');

  } catch (err) {
    console.error(err.toString());
  }
}

main();